+    pub fn recent_commits(&self, limit: usize) -> Result<Vec<SkillCommit>> {
+        if limit == 0 {
+            return Ok(Vec::new());
+        }
+
+        let mut revwalk = self.repo.revwalk()?;
+        match self.repo.head() {
+            Ok(head) => {
+                if let Some(oid) = head.target() {
+                    revwalk.push(oid)?;
+                } else {
+                    return Ok(Vec::new());
+                }
